import React, { useState, useEffect } from "react";
import axios from "axios";
import Table from "../Components/Table";

const UsedService = () => {
  const [form, setForm] = useState({ PhongSo: "", MaDV: "", SoLuong: "" });
  const [updateForm, setUpdateForm] = useState({ MaSD: "", SoLuong: "" });
  const [report, setReport] = useState([]);
  const [filter, setFilter] = useState({ PhongSo: "", MaKH: "" });
  const [editMode, setEditMode] = useState(false);

  const apiBase = "http://localhost:5000/api/usedservice";

  // Thêm dịch vụ
  const handleAdd = async (e) => {
    e.preventDefault();
    try {
      await axios.post(`${apiBase}/addusedservice`, form);
      alert("Thêm dịch vụ sử dụng thành công");
      setForm({ PhongSo: "", MaDV: "", SoLuong: "" });
      fetchReport();
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  // Cập nhật dịch vụ
  const handleUpdate = async (e) => {
    e.preventDefault();
    try {
      await axios.put(`${apiBase}/updateusedservice`, updateForm);
      alert("Cập nhật số lượng thành công");
      setUpdateForm({ MaSD: "", SoLuong: "" });
      setEditMode(false);
      fetchReport();
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  // Xóa dịch vụ
  const handleDelete = async (MaSD) => {
    if (!window.confirm("Bạn có chắc muốn xóa dịch vụ này?")) return;
    try {
      await axios.delete(`${apiBase}/deleteusedservice`, { data: { MaSD } });
      fetchReport();
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  // Lấy báo cáo
  const fetchReport = async () => {
    try {
      const params = {};
      if (filter.PhongSo) params.PhongSo = filter.PhongSo;
      if (filter.MaKH) params.MaKH = filter.MaKH;

      if (!params.PhongSo && !params.MaKH) {
        alert("Vui lòng nhập Phòng số hoặc Mã khách hàng để xem báo cáo");
        return;
      }

      const res = await axios.get(`${apiBase}/reportservice`, { params });
      const sorted = res.data.sort((a, b) => Number(a.PhongSo) - Number(b.PhongSo));
      setReport(sorted);
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  // Xem tất cả
  const fetchAll = async () => {
    try {
      const res = await axios.get(`${apiBase}/all`);
      const sorted = res.data.sort((a, b) => Number(a.PhongSo) - Number(b.PhongSo));
      setReport(sorted);
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  // Table columns
  const columns = report.length > 0
    ? [...Object.keys(report[0]).map((key) => ({ key, label: key })), { key: "actions", label: "Hành động" }]
    : [];

  const tableData = report.map((row) => ({
    ...row,
    actions: (
      <div className="flex justify-center items-center">
        <button
          onClick={() => handleDelete(row.MaSD)}
          className="bg-red-500 hover:bg-red-600 text-white px-3 py-1 rounded shadow flex items-center gap-1"
        >
          🗑 Xóa
        </button>
      </div>
    ),
  }));

  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold mb-4 text-blue-600">Quản lý dịch vụ đã dùng</h1>

      {/* Thêm dịch vụ */}
      <form className="mb-4 space-y-2" onSubmit={handleAdd}>
        <h2 className="font-semibold">Thêm dịch vụ cho phòng</h2>
        <input
          placeholder="Phòng số"
          value={form.PhongSo}
          onChange={(e) => setForm({ ...form, PhongSo: e.target.value })}
          className="border p-2 w-full rounded"
        />
        <input
          placeholder="Mã DV"
          value={form.MaDV}
          onChange={(e) => setForm({ ...form, MaDV: e.target.value })}
          className="border p-2 w-full rounded"
        />
        <input
          placeholder="Số lượng"
          type="number"
          value={form.SoLuong}
          onChange={(e) => setForm({ ...form, SoLuong: e.target.value })}
          className="border p-2 w-full rounded"
        />
        <button
          type="submit"
          className="bg-blue-500 hover:bg-blue-600 text-white px-4 py-2 rounded shadow"
        >
          ➕ Thêm dịch vụ
        </button>
      </form>

      {/* Cập nhật */}
      <form className="mb-4 space-y-2" onSubmit={handleUpdate}>
        <h2 className="font-semibold">Cập nhật số lượng dịch vụ</h2>
        <input
          placeholder="Mã SD"
          value={updateForm.MaSD}
          onChange={(e) => setUpdateForm({ ...updateForm, MaSD: e.target.value })}
          className="border p-2 w-full rounded"
          disabled={editMode}
        />
        <input
          placeholder="Số lượng mới"
          type="number"
          value={updateForm.SoLuong}
          onChange={(e) => setUpdateForm({ ...updateForm, SoLuong: e.target.value })}
          className="border p-2 w-full rounded"
        />
        <button
          type="submit"
          className="bg-green-500 hover:bg-green-600 text-white px-4 py-2 rounded shadow"
        >
          💾 Cập nhật số lượng
        </button>
      </form>

      {/* Filter */}
      <div className="mb-4 space-y-2">
        <h2 className="font-semibold">Báo cáo dịch vụ</h2>
        <input
          placeholder="Phòng số"
          value={filter.PhongSo}
          onChange={(e) => setFilter({ ...filter, PhongSo: e.target.value })}
          className="border p-2 w-full rounded"
        />
        <input
          placeholder="Mã khách hàng"
          value={filter.MaKH}
          onChange={(e) => setFilter({ ...filter, MaKH: e.target.value })}
          className="border p-2 w-full rounded"
        />
        <div className="flex space-x-2">
          <button onClick={fetchReport} className="bg-purple-500 hover:bg-purple-600 text-white px-4 py-2 rounded shadow">
            📊 Xem báo cáo
          </button>
          <button onClick={fetchAll} className="bg-green-500 hover:bg-green-600 text-white px-4 py-2 rounded shadow">
            Xem tất cả
          </button>
        </div>
      </div>

      {/* Table */}
      {report.length > 0 && <Table columns={columns} data={tableData} />}
    </div>
  );
};

export default UsedService;
